function drawSeasonGlyph(name, color, size){ return (SEASON_GLYPHS[name]||SEASON_GLYPHS.Breaking)(color,size); }
function drawLunarGlyph(name, color, size){ return (LUNAR_GLYPHS[name]||LUNAR_GLYPHS.Pilgrim)(color,size); }
function drawTreeGlyph(name, color){ return (TREE_GLYPHS[name]||TREE_GLYPHS.Birch)(color); }


