// ═══════════════════════════════════════════════════════════════════════
// CALCULATION LOGIC — real orbital mechanics, shared with the type calculator
// ═══════════════════════════════════════════════════════════════════════

function blendHex(h1, h2, w1, w2){
  const c1=[1,3,5].map(i=>parseInt(h1.substr(i,2),16));
  const c2=[1,3,5].map(i=>parseInt(h2.substr(i,2),16));
  const out=c1.map((v,i)=>Math.round(v*w1+c2[i]*w2));
  return '#'+out.map(v=>v.toString(16).padStart(2,'0')).join('').toUpperCase();
}
function getJulianDay(d){
  const y=d.getUTCFullYear(), m=d.getUTCMonth()+1, day=d.getUTCDate();
  const h=d.getUTCHours()/24+d.getUTCMinutes()/1440+d.getUTCSeconds()/86400;
  let Y=y, M=m;
  if(M<=2){ Y-=1; M+=12; }
  const A=Math.floor(Y/100), B=2-A+Math.floor(A/4);
  return Math.floor(365.25*(Y+4716))+Math.floor(30.6001*(M+1))+day+h+B-1524.5;
}
function norm360(x){ return ((x%360)+360)%360; }
function toRad(d){ return d*Math.PI/180; }
function solarEclipticLongitude(date){
  const JD=getJulianDay(date), T=(JD-2451545.0)/36525;
  const L0=norm360(280.46646+36000.76983*T+0.0003032*T*T);
  const M=norm360(357.52911+35999.05029*T-0.0001537*T*T);
  const Mr=toRad(M);
  const C=(1.914602-0.004817*T-0.000014*T*T)*Math.sin(Mr)
          +(0.019993-0.000101*T)*Math.sin(2*Mr)
          +0.000289*Math.sin(3*Mr);
  return norm360(L0+C);
}
function lunarPhaseDay(date){
  const ref=Date.UTC(2000,0,6,18,14,0);
  const diff=(date.getTime()-ref)/86400000;
  return((diff%SYNODIC_MONTH)+SYNODIC_MONTH)%SYNODIC_MONTH;
}
function nearestCyclicIndex(value, anchors, cycleLength){
  let bestIdx=0, bestDist=Infinity;
  anchors.forEach((a,i)=>{ let d=Math.abs(value-a); d=Math.min(d,cycleLength-d); if(d<bestDist){bestDist=d;bestIdx=i;} });
  return bestIdx;
}
function hashString(str){ let h=0; for(let i=0;i<str.length;i++) h=Math.imul(31,h)+str.charCodeAt(i)|0; return h>>>0; }
function mulberry32(seed){ return function(){ seed|=0; seed=seed+0x6D2B79F5|0; let t=Math.imul(seed^seed>>>15,1|seed); t=t+Math.imul(t^t>>>7,61|t)^t; return((t^t>>>14)>>>0)/4294967296; }; }
function generatePoints(seedStr, count, w, h){
  const rand=mulberry32(hashString(seedStr)), pts=[];
  for(let i=0;i<count;i++) pts.push({x:24+rand()*(w-48), y:18+rand()*(h-36)});
  return pts;
}
function renderConstellation(seedName, comboColor){
  const svg=document.getElementById('constellation');
  svg.innerHTML='';
  const w=240, h=130;
  const pts=generatePoints(seedName, 7, w, h);
  const ns="http://www.w3.org/2000/svg";
  for(let i=0;i<pts.length-1;i++){
    const ln=document.createElementNS(ns,'line');
    ln.setAttribute('x1',pts[i].x); ln.setAttribute('y1',pts[i].y);
    ln.setAttribute('x2',pts[i+1].x); ln.setAttribute('y2',pts[i+1].y);
    ln.setAttribute('stroke',comboColor); ln.setAttribute('stroke-width','1.2'); ln.setAttribute('opacity','.45');
    const len=Math.hypot(pts[i+1].x-pts[i].x,pts[i+1].y-pts[i].y);
    ln.style.strokeDasharray=len; ln.style.strokeDashoffset=len;
    ln.style.transition=`stroke-dashoffset 0.6s ease ${0.12+i*0.1}s`;
    svg.appendChild(ln);
    requestAnimationFrame(()=>requestAnimationFrame(()=>{ ln.style.strokeDashoffset='0'; }));
  }
  pts.forEach((p,i)=>{
    const c=document.createElementNS(ns,'circle');
    c.setAttribute('cx',p.x); c.setAttribute('cy',p.y); c.setAttribute('r',i===0?4:2.8);
    c.setAttribute('fill',comboColor); c.classList.add('star');
    c.style.animationDelay=`${0.08+i*0.07}s`;
    svg.appendChild(c);
    requestAnimationFrame(()=>c.classList.add('show'));
  });
}

function calculatePerson(month,day,year){
  const date=new Date(year,month-1,day);
  if(date.getFullYear()!==year||date.getMonth()!==month-1||date.getDate()!==day) return null;
  const cd=new Date(Date.UTC(year,month-1,day,12,0,0));
  const solarLong=solarEclipticLongitude(cd);
  const seasonIdx=nearestCyclicIndex(solarLong,SEASON_POINTS.map(p=>p.angle),360);
  const season=SEASON_POINTS[seasonIdx];
  const moonDay=lunarPhaseDay(cd);
  const lunarIdx=nearestCyclicIndex(moonDay,LUNAR_PHASES.map(p=>p.day),SYNODIC_MONTH);
  const lunar=LUNAR_PHASES[lunarIdx];
  const comboColor=blendHex(season.color,lunar.color,0.55,0.45);
  return{season,lunar,comboColor,solarLong,moonDay};
}

