function buildProfileBlock(blockEl, toggleLabel, colorDot, bodyHTML){
  blockEl.innerHTML=`
    <button class="profile-toggle" onclick="this.classList.toggle('open');this.nextElementSibling.classList.toggle('open')">
      <span><span class="swatch-inline" style="background:${colorDot}"></span>${toggleLabel}</span>
      <span class="arrow">▾</span>
    </button>
    <div class="profile-body">${bodyHTML}</div>`;
}

function corrCardTree(season){
  return `<div class="corr-card">
      <span class="corr-icon">${drawTreeGlyph(season.tree, season.color)}</span>
      <div>
        <div class="corr-label">Birth tree</div>
        <div class="corr-name" style="color:${season.color}">${season.tree}</div>
        <div class="corr-desc">${season.treeDesc}</div>
      </div>
    </div>`;
}
function corrCardAnimal(lunar){
  return `<div class="corr-card">
      <img class="corr-animal-img" src="${ANIMAL_IMAGES[lunar.animal]}" alt="${lunar.animal}"/>
      <div>
        <div class="corr-label">Birth animal</div>
        <div class="corr-name" style="color:${lunar.color}">${lunar.animal}</div>
        <div class="corr-desc">${lunar.animalDesc}</div>
      </div>
    </div>`;
}

