// REVEAL
// ═══════════════════════════════════════════════════════════════════════

document.getElementById('revealBtn').addEventListener('click',()=>{
  const nameA=(document.getElementById('nameA').value||'Person A').trim();
  const nameB=(document.getElementById('nameB').value||'Person B').trim();
  const mA=parseInt(document.getElementById('monthA').value,10);
  const dA=parseInt(document.getElementById('dayA').value,10);
  const yA=parseInt(document.getElementById('yearA').value,10);
  const mB=parseInt(document.getElementById('monthB').value,10);
  const dB=parseInt(document.getElementById('dayB').value,10);
  const yB=parseInt(document.getElementById('yearB').value,10);
  const err=document.getElementById('errorMsg');

  if(!dA||!yA||yA<1900||yA>2100||!dB||!yB||yB<1900||yB>2100){
    err.textContent="Enter two complete, valid birthdates to continue."; return;
  }
  const rA=calculatePerson(mA,dA,yA);
  const rB=calculatePerson(mB,dB,yB);
  if(!rA||!rB){ err.textContent="One of those dates doesn't exist on the calendar — double-check the day."; return; }
  err.textContent='';

  const seasonKey=seasonPairKey(rA.season.name,rB.season.name);
  const seasonPair=SEASON_PAIR_INFO[seasonKey];
  const seasonFamily=SEASON_FAMILY_INFO[seasonPair.family];

  const lunarKey=lunarPairKey(rA.lunar.name,rB.lunar.name);
  const lunarPair=LUNAR_PAIR_INFO[lunarKey];
  const lunarFamily=LUNAR_FAMILY_INFO[lunarPair.family];

  const combined=COMBINED_INFO[seasonPair.family+'|'+lunarPair.family];

  const overallColor=blendHex(rA.comboColor, rB.comboColor, 0.5, 0.5);

  // Pair header
  document.getElementById('pairHeader').innerHTML=`
    <div class="person-col">
      <div class="person-name">${nameA}</div>
      <div class="person-icons">${drawSeasonGlyph(rA.season.name,rA.season.color,40)}${drawLunarGlyph(rA.lunar.name,rA.lunar.color,40)}</div>
      <div class="person-types">${rA.season.name} · ${rA.lunar.name}</div>
    </div>
    <div class="pair-sep">×</div>
    <div class="person-col">
      <div class="person-name">${nameB}</div>
      <div class="person-icons">${drawSeasonGlyph(rB.season.name,rB.season.color,40)}${drawLunarGlyph(rB.lunar.name,rB.lunar.color,40)}</div>
      <div class="person-types">${rB.season.name} · ${rB.lunar.name}</div>
    </div>`;

  renderConstellation(seasonKey+'|'+lunarKey, overallColor);

  document.getElementById('resultName').textContent=combined.name;
  document.getElementById('resultFn').textContent=`${seasonPair.family} Season Pairing · ${lunarPair.family} Lunar Pairing`;
  document.getElementById('taglineText').textContent=`"${combined.feels}"`;
  document.getElementById('motifDesc').innerHTML=`<span class="swatch-inline" style="background:${overallColor}"></span>Function: ${combined.fn}.`;

  document.getElementById('chipsRow').innerHTML=`
    <span class="chip">Season: <b>${rA.season.name} + ${rB.season.name}</b></span>
    <span class="chip">${seasonPair.family} · distance ${seasonFamily.distance}</span>
    <span class="chip">Moon: <b>${rA.lunar.name} + ${rB.lunar.name}</b></span>
    <span class="chip">${lunarPair.family}</span>`;

  document.getElementById('corrLabelA').textContent=`${nameA}'s correspondences`;
  document.getElementById('correspondencesA').innerHTML = corrCardTree(rA.season) + corrCardAnimal(rA.lunar);
  document.getElementById('corrLabelB').textContent=`${nameB}'s correspondences`;
  document.getElementById('correspondencesB').innerHTML = corrCardTree(rB.season) + corrCardAnimal(rB.lunar);

  // Season pairing accordion
  const seasonLabel = rA.season.name===rB.season.name
    ? `Season Point Pairing: ${rA.season.name} + ${rA.season.name} (${seasonPair.family})`
    : `Season Point Pairing: ${rA.season.name} × ${rB.season.name} (${seasonPair.family})`;
  buildProfileBlock(document.getElementById('blockSeason'), seasonLabel, overallColor, `
    <p><span class="label">${seasonPair.family} — ${seasonFamily.subtitle}</span>${seasonFamily.desc}</p>
    <p><span class="label">This pairing's dynamic</span>${seasonPair.flow}</p>
    <p class="quote">"${seasonPair.quote}"</p>
    <p><span class="label">Where it tends to show up</span>${seasonPair.domain}</p>
    <p><span class="label">Watch for</span>${seasonPair.risk}</p>
  `);

  // Lunar pairing accordion
  const lunarLabel = rA.lunar.name===rB.lunar.name
    ? `Lunar Phase Pairing: ${rA.lunar.name} + ${rA.lunar.name} (Same-Phase)`
    : `Lunar Phase Pairing: ${rA.lunar.name} × ${rB.lunar.name} (${lunarPair.family})`;
  buildProfileBlock(document.getElementById('blockLunar'), lunarLabel, overallColor, `
    <p><span class="label">${lunarPair.family} — ${lunarFamily.subtitle}</span></p>
    <p><span class="label">${lunarPair.name}</span>${lunarPair.desc}</p>
  `);

  // Combined archetype accordion
  buildProfileBlock(document.getElementById('blockCombo'), `Combined Archetype: ${combined.name}`, overallColor, `
    <p><span class="label">Core dynamic</span>${seasonPair.family} season pairing × ${lunarPair.family} lunar pairing.</p>
    <p><span class="label">Function</span>${combined.fn}</p>
    <p><span class="label">Feels like</span><span class="quote">"${combined.feels}"</span></p>
    <p><span class="label">Typical risk</span>${combined.risk}</p>
  `);

  document.getElementById('formView').style.display='none';
  document.getElementById('resultView').classList.add('visible');
});

document.getElementById('resetLink').addEventListener('click',()=>{
  document.getElementById('resultView').classList.remove('visible');
  document.getElementById('formView').style.display='block';
  document.getElementById('errorMsg').textContent='';
  document.querySelectorAll('.profile-toggle.open').forEach(t=>t.classList.remove('open'));
  document.querySelectorAll('.profile-body.open').forEach(b=>b.classList.remove('open'));
});